const PrivateRoute = ({ children, roleRequired }) => {
    const { user, isAuthenticated, loading } = useAuth();

    if (loading) return <div style={{textAlign: 'center', marginTop: '50px'}}>Cargando...</div>;

    if (!isAuthenticated) return <Navigate to="/login" />;

    // Normalizamos el rol para la comparación
    const currentRol = String(user?.rol || user?.role || '').toLowerCase().trim();

    if (roleRequired && currentRol !== roleRequired.toLowerCase().trim()) {
        console.warn(`Acceso denegado. Requerido: ${roleRequired}, Actual: ${currentRol}`);
        return <Navigate to="/" />;
    }

    return children;
};
